        "viz_TfOg5oXQ": {
            "type": "splunk.table",
            "title": "Server Profile Config State",
            "dataSources": {
                "primary": "ds_CETdq1yO"
            },
            "options": {
                "drilldown": "none",
                "showInternalFields": false,
                "backgroundColor": "> themes.defaultBackgroundColor",
                "columnFormat": {
                    "Config State Summary": {
                        "rowBackgroundColors": "> table | seriesByName(\"Config State Summary\") | matchValue(Config_State_SummaryColumnColorConfig)",
                        "rowColors": "> table | seriesByName(\"Config State Summary\") | matchValue(Config_State_Summary2ColumnColorConfig)"
                    }
                }
            },
            "context": {
                "Config_State_SummaryColumnColorConfig": [
                    {
                        "match": "Assigned",
                        "value": "#118832"
                    },
                    {
                        "match": "Associated",
                        "value": "#55C169"
                    },
                    {
                        "match": "Failed",
                        "value": "#9E2520"
                    },
                    {
                        "match": "Inconsistent",
                        "value": "#D94E17"
                    },
                    {
                        "match": "Not-assigned",
                        "value": "#CBA700"
                    },
                    {
                        "match": "Waiting-for-resource",
                        "value": "#1182F3"
                    }
                ],
                "Config_State_Summary2ColumnColorConfig": [
                    {
                        "match": "Failed",
                        "value": "#FFFFFF"
                    },
                    {
                        "match": "Inconsistent",
                        "value": "#FFFFFF"
                    },
                    {
                        "match": "Assigned",
                        "value": "#FFFFFF"
