    "dataSources": {
        "ds_efqDXlnk": {
            "type": "ds.search",
            "options": {
                "queryParameters": {
                    "earliest": "$tr_xAEB84dN.earliest$",
                    "latest": "$tr_xAEB84dN.latest$"
                },
                "query": "`cisco_intersight_index` sourcetype=\"cisco:intersight:alarms\" Name=\"ServerProfile*\"\n| search account_name IN ($account_name$)\n| where Severity != \"Cleared\"\n| dedup Moid\n| stats count by Name"
            },
            "name": "Total Active Alarms related to Server Profile"
        },
        "ds_d0DCctlb": {
            "type": "ds.search",
            "options": {
                "queryParameters": {
                    "earliest": "$tr_xAEB84dN.earliest$",
                    "latest": "$tr_xAEB84dN.latest$"
                },
                "query": "| inputlookup cisco_intersight_server_profiles\n| where splunk_managed_lifecycle == \"PRESENT\" \n| search account_name IN ($account_name$)\n| dedup Moid\n| stats count as TotalServerProfile"
            },
            "name": "Total Number of Server Profile"
        },
        "ds_U0lHMUTt": {
            "type": "ds.search",
            "options": {
                "queryParameters": {
                    "earliest": "$tr_xAEB84dN.earliest$",
                    "latest": "$tr_xAEB84dN.latest$"
                },
                "query": "`cisco_intersight_index` sourcetype=\"cisco:intersight:alarms\" Name=\"ServerProfile*\"\n| where Severity != \"Cleared\"\n| dedup Moid\n| search account_name IN ($account_name$)\n| rename AffectedMo.Moid as AffectedMoMoid\n| join type=left AffectedMoMoid [ | inputlookup cisco_intersight_server_profiles | where splunk_managed_lifecycle == \"PRESENT\" | rename Moid as AffectedMoMoid, Name as ServerProfileName, AssignedServer.Name as AssignedServerName, AssignedServer.Moid as AssignedServerMoid, AssignedServer.ObjectType as AssignedServerObjectType | table AffectedMoMoid, ServerProfileName, ServerAssignmentMode, ManagementMode, DeployStatus, AssignedServerName, AssignedServerMoid, AssignedServerObjectType ]\n| stats count"
            },
            "name": "Total Number of Server Profile with Alarms"
        },
        "ds_gNGCu4b0_ds_efqDXlnk": {
            "type": "ds.search",
            "options": {
                "queryParameters": {
                    "earliest": "$tr_xAEB84dN.earliest$",
                    "latest": "$tr_xAEB84dN.latest$"
                },
                "query": "`cisco_intersight_index` sourcetype=\"cisco:intersight:alarms\" Name=\"ServerProfile*\"\n| search account_name IN ($account_name$)\n| where Severity != \"Cleared\"\n| dedup Moid\n| stats count by Severity"
            },
            "name": "Total Active Alarms related to Server Profile by Severity"
        },
        "ds_5oa35wJQ": {
            "type": "ds.search",
            "options": {
                "queryParameters": {
                    "earliest": "$tr_xAEB84dN.earliest$",
                    "latest": "$tr_xAEB84dN.latest$"
                },
                "query": "| inputlookup cisco_intersight_server_profiles | where splunk_managed_lifecycle == \"PRESENT\" \n| search account_name IN ($account_name$)\n| dedup Moid\n| stats count by TargetPlatform"
            },
            "name": "Target Platform"
        },
        "ds_3kXnyvOL_ds_5oa35wJQ": {
            "type": "ds.search",
            "options": {
                "queryParameters": {
                    "earliest": "$tr_xAEB84dN.earliest$",
                    "latest": "$tr_xAEB84dN.latest$"
                },
                "query": "| inputlookup cisco_intersight_server_profiles\n| where splunk_managed_lifecycle == \"PRESENT\" \n| search account_name IN ($account_name$)\n| dedup Moid\n| where TemplateSyncStatus!=\"None\"\n| eval TemplateSyncStatus=case(\n    TemplateSyncStatus=\"OK\", \"In Sync\",\n    true(), TemplateSyncStatus\n)\n| stats count by TemplateSyncStatus"
            },
            "name": "Template Sync Status"
        },
        "ds_jEaramOl_ds_5oa35wJQ": {
            "type": "ds.search",
            "options": {
                "queryParameters": {
                    "earliest": "$tr_xAEB84dN.earliest$",
