                "query": "| inputlookup cisco_intersight_server_profiles | where splunk_managed_lifecycle == \"PRESENT\"\r\n| fillnull value=\"-\"\r\n| search account_name IN ($account_name$)\r\n| stats count by AssignedServer.Moid, Name, ConfigContext.ConfigStateSummary, AssignedServer.Name \r\n| rename AssignedServer.Name as ServerName\r\n| rename AssignedServer.Moid as servermoid \r\n| rename Name as Name \r\n| rename ConfigContext.ConfigStateSummary as ConfigStateSummary \r\n| eval servermoid_search = if(isnull(servermoid) OR len(servermoid) == 0, \"\", servermoid) \r\n| search ServerName=\"*$servername$*\"\r\n| search Name=\"*$serverprofilename$*\"\r\n| search ConfigStateSummary=$configstatesummary$\r\n| rename Name as \"Server Profile Name\", ServerName as \"Server Name\", ConfigStateSummary as \"Config State Summary\"\r\n| eval sort_field = case(\r\n'Config State Summary' == \"Assigned\", 6,\r\n'Config State Summary' == \"Associated\", 5,\r\n'Config State Summary' == \"Failed\", 1,\r\n'Config State Summary' == \"Inconsistent\", 2,\r\n'Config State Summary' == \"Not-assigned\", 3,\r\n'Config State Summary' == \"Waiting-for-resource\", 4\r\n) \r\n| eval sort_field = tonumber(sort_field) \r\n| sort 0 sort_field \r\n| table \"Server Profile Name\", \"Server Name\", \"Config State Summary\""
            },
